describe('string_content', () => {
  it('factory produces correct type', () => {
    const node = ir.stringContent("test");
    expect(node.$type).toBe(TSKindId.StringContent);
    expect(node.$source).toBe(2);
    expect(node.$text).toBe("test");
  });
});

